(function(w){"use strict";const ID="ohms-law";function n(v){return v===null||v===undefined||v===""?NaN:Number(v)}function compute(x){const v=n(x.voltage),i=n(x.current),r=n(x.resistance),valid=[v,i,r].filter(Number.isFinite).length;if(valid!==2)return{error:"전압·전류·저항 중 정확히 두 값을 입력해 주세요."};if(!Number.isFinite(v))return{kind:"voltage",value:i*r};if(!Number.isFinite(i)){if(r===0)return{error:"저항은 0일 수 없습니다."};return{kind:"current",value:v/r}}if(!Number.isFinite(r)){if(i===0)return{error:"전류는 0일 수 없습니다."};return{kind:"resistance",value:v/i}}return{error:"입력값을 확인해 주세요."}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><p class="hm-calc-hint">구하려는 값 하나는 비워 두고 나머지 두 값을 입력하세요.</p><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>전압 V (볼트)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>전류 I (암페어)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>저항 R (옴)</label><input class="hm-calc-input" inputmode="decimal"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">옴의 법칙 계산</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const vals=Array.from(inputs).map(i=>i.value.trim()===''?'':api.parseNumber(i.value)),r=compute({voltage:vals[0],current:vals[1],resistance:vals[2]});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}const m={voltage:['전압','V'],current:['전류','A'],resistance:['저항','Ω']}[r.kind];api.setMessage(msg,"");api.setResult(res,api.resultCard(m[0],`${api.formatNumber(r.value,8)} ${m[1]}`,'V = I × R'));});}
w.HM_CALC.register(ID,{compute,render});})(window);
